SELECT DISTINCT org.id , org.group_id AS groupId , org.org_type AS orgType, org.parent_id AS parentId , org.org_code AS orgCode, org.parent_bu_id AS parentBUId , org.org_name AS orgName , org.state AS state, org.main_org_flag AS mainOrgFlag FROM base_organization org LEFT JOIN base_organization_function fun ON org.id = fun.org_id WHERE org.state = 1 and org.org_type in (2,3) and org.group_id = #{groupId} and org.id in
#{orgId}
AND fun.function_type in (
#{func}
)

