select a.*, b.org_name as parentBuName, c.org_name as parentName from base_organization a left join base_organization b on a.`parent_bu_id` = b.`id` left join base_organization c on a.parent_id =c.id where a.deleted_flag=0
and a. parent_id =#{queryParam.parentId}
and a.parent_bu_id in (
#{item}
)
and a.org_code LIKE CONCAT('%',#{queryParam.orgCode},'%')
and a.org_name like CONCAT('%',#{queryParam.orgName},'%')
and a.state =#{queryParam.state}
and a.org_type =#{queryParam.orgType}

